#!/usr/bin/env python3

import argparse
import sys
import re
import os
import json
from kafka.admin import KafkaAdminClient, NewTopic, ConfigResource, ConfigResourceType
from kafka.errors import KafkaError, TopicAlreadyExistsError
import logging

logging.basicConfig(level=logging.INFO, format='%(asctime)s - %(levelname)s - %(message)s')
logger = logging.getLogger(__name__)

ALLOWED_TOPIC_NAME_PATTERN = re.compile(r'^[a-zA-Z0-9._-]{1,249}$')
ALLOWED_CONFIG_KEYS = {
    'cleanup.policy', 'compression.type', 'delete.retention.ms', 
    'file.delete.delay.ms', 'flush.messages', 'flush.ms',
    'follower.replication.throttled.replicas', 'index.interval.bytes',
    'leader.replication.throttled.replicas', 'max.compaction.lag.ms',
    'max.message.bytes', 'message.downconversion.enable',
    'message.format.version', 'message.timestamp.difference.max.ms',
    'message.timestamp.type', 'min.cleanable.dirty.ratio',
    'min.compaction.lag.ms', 'min.insync.replicas', 'preallocate',
    'retention.bytes', 'retention.ms', 'segment.bytes', 'segment.index.bytes',
    'segment.jitter.ms', 'segment.ms', 'unclean.leader.election.enable'
}

MIN_PARTITIONS = 1
MAX_PARTITIONS = 1000
MIN_REPLICATION_FACTOR = 1
MAX_REPLICATION_FACTOR = 10

def validate_topic_name(topic_name):
    if not topic_name:
        raise ValueError("Topic name cannot be empty")
    if not ALLOWED_TOPIC_NAME_PATTERN.match(topic_name):
        raise ValueError(f"Invalid topic name: {topic_name}. Must match pattern: {ALLOWED_TOPIC_NAME_PATTERN.pattern}")
    if topic_name.startswith('.') or topic_name.startswith('_'):
        raise ValueError(f"Topic name cannot start with '.' or '_': {topic_name}")
    return topic_name

def validate_partitions(partitions):
    try:
        p = int(partitions)
        if p < MIN_PARTITIONS or p > MAX_PARTITIONS:
            raise ValueError(f"Partitions must be between {MIN_PARTITIONS} and {MAX_PARTITIONS}")
        return p
    except (ValueError, TypeError):
        raise ValueError(f"Invalid partition count: {partitions}")

def validate_replication_factor(replication_factor):
    try:
        rf = int(replication_factor)
        if rf < MIN_REPLICATION_FACTOR or rf > MAX_REPLICATION_FACTOR:
            raise ValueError(f"Replication factor must be between {MIN_REPLICATION_FACTOR} and {MAX_REPLICATION_FACTOR}")
        return rf
    except (ValueError, TypeError):
        raise ValueError(f"Invalid replication factor: {replication_factor}")

def validate_config(config_dict):
    if not isinstance(config_dict, dict):
        raise ValueError("Configuration must be a dictionary")
    
    validated_config = {}
    for key, value in config_dict.items():
        if key not in ALLOWED_CONFIG_KEYS:
            raise ValueError(f"Configuration key '{key}' is not allowed")
        
        if not isinstance(value, str):
            value = str(value)
        
        if len(value) > 1000:
            raise ValueError(f"Configuration value for '{key}' is too long")
        
        validated_config[key] = value
    
    return validated_config

def get_kafka_bootstrap_servers():
    servers = os.environ.get('KAFKA_BOOTSTRAP_SERVERS')
    if not servers:
        raise ValueError("KAFKA_BOOTSTRAP_SERVERS environment variable must be set")
    
    server_list = [s.strip() for s in servers.split(',')]
    for server in server_list:
        if not re.match(r'^[a-zA-Z0-9.-]+:\d{1,5}$', server):
            raise ValueError(f"Invalid bootstrap server format: {server}")
    
    return servers

def get_kafka_security_config():
    config = {}
    
    security_protocol = os.environ.get('KAFKA_SECURITY_PROTOCOL', 'PLAINTEXT')
    if security_protocol not in ['PLAINTEXT', 'SSL', 'SASL_PLAINTEXT', 'SASL_SSL']:
        raise ValueError(f"Invalid security protocol: {security_protocol}")
    config['security_protocol'] = security_protocol
    
    if security_protocol in ['SASL_PLAINTEXT', 'SASL_SSL']:
        sasl_mechanism = os.environ.get('KAFKA_SASL_MECHANISM')
        if sasl_mechanism not in ['PLAIN', 'SCRAM-SHA-256', 'SCRAM-SHA-512', 'GSSAPI']:
            raise ValueError(f"Invalid SASL mechanism: {sasl_mechanism}")
        config['sasl_mechanism'] = sasl_mechanism
        
        username = os.environ.get('KAFKA_SASL_USERNAME')
        password = os.environ.get('KAFKA_SASL_PASSWORD')
        if not username or not password:
            raise ValueError("KAFKA_SASL_USERNAME and KAFKA_SASL_PASSWORD must be set for SASL authentication")
        config['sasl_plain_username'] = username
        config['sasl_plain_password'] = password
    
    if security_protocol in ['SSL', 'SASL_SSL']:
        ssl_cafile = os.environ.get('KAFKA_SSL_CAFILE')
        if ssl_cafile:
            if not os.path.isfile(ssl_cafile):
                raise ValueError(f"SSL CA file not found: {ssl_cafile}")
            config['ssl_cafile'] = ssl_cafile
        
        ssl_certfile = os.environ.get('KAFKA_SSL_CERTFILE')
        ssl_keyfile = os.environ.get('KAFKA_SSL_KEYFILE')
        if ssl_certfile and ssl_keyfile:
            if not os.path.isfile(ssl_certfile):
                raise ValueError(f"SSL cert file not found: {ssl_certfile}")
            if not os.path.isfile(ssl_keyfile):
                raise ValueError(f"SSL key file not found: {ssl_keyfile}")
            config['ssl_certfile'] = ssl_certfile
            config['ssl_keyfile'] = ssl_keyfile
    
    return config

def create_admin_client():
    bootstrap_servers = get_kafka_bootstrap_servers()
    security_config = get_kafka_security_config()
    
    admin_config = {
        'bootstrap_servers': bootstrap_servers,
        'client_id': 'kafka-admin-script',
        'request_timeout_ms': 30000,
        'api_version_auto_timeout_ms': 10000
    }
    admin_config.update(security_config)
    
    return KafkaAdminClient(**admin_config)

def create_topic(admin_client, topic_name, partitions, replication_factor, config):
    try:
        validated_topic = validate_topic_name(topic_name)
        validated_partitions = validate_partitions(partitions)
        validated_rf = validate_replication_factor(replication_factor)
        validated_config = validate_config(config) if config else {}
        
        new_topic = NewTopic(
            name=validated_topic,
            num_partitions=validated_partitions,
            replication_factor=validated_rf,
            topic_configs=validated_config
        )
        
        result = admin_client.create_topics([new_topic], validate_only=False)
        
        for topic, future in result.items():
            try:
                future.result()
                logger.info(f"Topic '{topic}' created successfully")
            except TopicAlreadyExistsError:
                logger.warning(f"Topic '{topic}' already exists")
            except Exception as e:
                logger.error(f"Failed to create topic '{topic}': {e}")
                raise
                
    except Exception as e:
        logger.error(f"Error creating topic: {e}")
        raise

def delete_topic(admin_client, topic_name):
    try:
        validated_topic = validate_topic_name(topic_name)
        
        result = admin_client.delete_topics([validated_topic])
        
        for topic, future in result.items():
            try:
                future.result()
                logger.info(f"Topic '{topic}' deleted successfully")
            except Exception as e:
                logger.error(f"Failed to delete topic '{topic}': {e}")
                raise
                
    except Exception as e:
        logger.error(f"Error deleting topic: {e}")
        raise

def list_topics(admin_client):
    try:
        metadata = admin_client.list_topics()
        logger.info("Available topics:")
        for topic in sorted(metadata):
            logger.info(f"  - {topic}")
        return metadata
    except Exception as e:
        logger.error(f"Error listing topics: {e}")
        raise

def describe_topic(admin_client, topic_name):
    try:
        validated_topic = validate_topic_name(topic_name)
        
        metadata = admin_client.list_topics()
        if validated_topic not in metadata:
            logger.error(f"Topic '{validated_topic}' does not exist")
            return
        
        topic_metadata = metadata[validated_topic]
        logger.info(f"Topic: {validated_topic}")
        logger.info(f"  Partitions: {len(topic_metadata['partitions'])}")
        
        for partition_id, partition_info in topic_metadata['partitions'].items():
            logger.info(f"    Partition {partition_id}:")
            logger.info(f"      Leader: {partition_info['leader']}")
            logger.info(f"      Replicas: {partition_info['replicas']}")
            logger.info(f"      ISR: {partition_info['isr']}")
        
        config_resource = ConfigResource(ConfigResourceType.TOPIC, validated_topic)
        configs = admin_client.describe_configs([config_resource])
        
        for resource, future in configs.items():
            config_dict = future.result()
            logger.info(f"  Configuration:")
            for config_name, config_entry in config_dict.items():
                if not config_entry.is_default:
                    logger.info(f"    {config_name}: {config_entry.value}")
                    
    except Exception as e:
        logger.error(f"Error describing topic: {e}")
        raise

def alter_topic_config(admin_client, topic_name, config):
    try:
        validated_topic = validate_topic_name(topic_name)
        validated_config = validate_config(config)
        
        config_resource = ConfigResource(
            ConfigResourceType.TOPIC,
            validated_topic,
            configs=validated_config
        )
        
        result = admin_client.alter_configs([config_resource])
        
        for resource, future in result.items():
            try:
                future.result()
                logger.info(f"Configuration for topic '{validated_topic}' updated successfully")
            except Exception as e:
                logger.error(f"Failed to update configuration for topic '{validated_topic}': {e}")
                raise
                
    except Exception as e:
        logger.error(f"Error altering topic configuration: {e}")
        raise

def main():
    parser = argparse.ArgumentParser(description='Kafka Cluster Administration Tool')
    subparsers = parser.add_subparsers(dest='command', help='Command to execute')
    
    create_parser = subparsers.add_parser('create', help='Create a new topic')
    create_parser.add_argument('--topic', required=True, help='Topic name')
    create_parser.add_argument('--partitions', type=int, default=1, help='Number of partitions')
    create_parser.add_argument('--replication-factor', type=int, default=1, help='Replication factor')
    create_parser.add_argument('--config', help='Topic configuration as JSON string')
    
    delete_parser = subparsers.add_parser('delete', help='Delete a topic')
    delete_parser.add_argument('--topic', required=True, help='Topic name')
    
    list_parser = subparsers.add_parser('list', help='List all topics')
    
    describe_parser = subparsers.add_parser('describe', help='Describe a topic')
    describe_parser.add_argument('--topic', required=True, help='Topic name')
    
    alter_parser = subparsers.add_parser('alter', help='Alter topic configuration')
    alter_parser.add_argument('--topic', required=True, help='Topic name')
    alter_parser.add_argument('--config', required=True, help='Topic configuration as JSON string')
    
    args = parser.parse_args()
    
    if not args.command:
        parser.print_help()
        sys.exit(1)
    
    try:
        admin_client = create_admin_client()
        
        if args.command == 'create':
            config = {}
            if args.config:
                try:
                    config = json.loads(args.config)
                except json.JSONDecodeError as e:
                    logger.error(f"Invalid JSON configuration: {e}")
                    sys.exit(1)
            
            create_topic(admin_client, args.topic, args.partitions, args.replication_factor, config)
            
        elif args.command == 'delete':
            delete_topic(admin_client, args.topic)
            
        elif args.command == 'list':
            list_topics(admin_client)
            
        elif args.command == 'describe':
            describe_topic(admin_client, args.topic)
            
        elif args.command == 'alter':
            try:
                config = json.loads(args.config)
            except json.JSONDecodeError as e:
                logger.error(f"Invalid JSON configuration: {e}")
                sys.exit(1)
            
            alter_topic_config(admin_client, args.topic, config)
        
        admin_client.close()
        
    except Exception as e:
        logger.error(f"Fatal error: {e}")
        sys.exit(1)

if __name__ == '__main__':
    main()